module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 1,
version: '1.0.0',
    name: 'out',
    aliases: ['leave', 'bye'],
    description: 'Bot leaves the group',
    usage: 'out',
    category: 'Group',
    groupOnly: true,
    prefix: true,
    adminOnly: true
  },
  
  async run({ api, event, send, config }) {
    const { threadID } = event;
    const botID = api.getCurrentUserID();
    
    await send.reply(`━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n${config.BOTNAME} 𝐢𝐬 𝐥𝐞𝐚𝐯𝐢𝐧𝐠. 🅖𝐨𝐨𝐝𝐛𝐲𝐞!\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━`);
    
    setTimeout(() => {
      api.removeUserFromGroup(botID, threadID);
    }, 2000);
  }
};
